// Import statements.
import akka.actor._
import akka.http.scaladsl.{ Http, HttpRequest }
import akka.http.scaladsl.model.{ HttpRequest => AhHttpRequest }
import akka.http.scaladsl.unmarshalling.Unmarshal
import org.json4s.native.JsonMethods
import org.slf4j._


// The root of the service. This is a singleton actor that listens for incoming messages and responds accordingly.
class ApiService extends Actor {

    override def receive: Receive = {
        case AhHttpRequest(request, _) =>
            Http()
              .singleRequest(HttpRequest(url = request.uri))
              .flatMap{
                case response => Unmarshal[String](response)
              }
              .map{
                case s =>
                  logger.debug("unmarshalled content to string: {}", s)
                  Ok(s).withHeaders(Map(("Content-Type", "text/plain")))
              }
              .run()
    }
}


object ApiServiceApp {

    def main(args: Array[String]): Unit = {
        // Your code here.
        val sys     = ActorSystem("ApiService")

        sys.actorOf(Props(new ApiService))

        // Start the HTTP server and listen for requests.
        val bindingFuture = Http().bindAndHandle(
            new Resource, "localhost", 3097
        )

        // Wait for the binding to be completed.
        println(s"Listening for requests at ${bindingFuture.get}")
    }
}


